function make_longitudinal_QC_and_requested_analyses_NEWCOHORT_2026_FINAL()
% Schema-strict QC + requested analyses for NEW COHORT / NEW TIMELINE.
%
% INPUT:  ALL_mice_longitudinal.csv generated by:
%   Longitudinal_final_trialrequire_HOTTST_passive_final_handle_nomatchingstrabu.m
%
% OUTPUT: figures + CSV summaries under:
%   <latest run_*/QC_AND_REQUESTED_ANALYSES_<timestamp>/>
%
% IMPORTANT: This script does NOT guess schema.
% It REQUIRES specific column names and errors clearly if missing.

%% ===================== USER CONFIG =====================
cfg = struct();

% Root
cfg.rootTry = 'K:\addiction_concate_Dec_2025\longitudinal_outputs';

% Days
cfg.ignoreDays      = [1 2];              % habituation
cfg.transitionDays  = [4 6 11 14 17];      % “less reliable” (edit if you want)

% Timeline phases (fixed)
cfg.phaseNames = ["PRE","DURING","POST","WITHDRAWAL","REEXPOSURE"];

% Phase day ranges
cfg.phaseDays.PRE        = 3:5;
cfg.phaseDays.DURING     = 6:10;
cfg.phaseDays.POST       = 11:13;
cfg.phaseDays.WITHDRAWAL = 14:16;
cfg.phaseDays.REEXPOSURE = 17:18;

% Pupil normalization baseline day (per mouse)
cfg.pupilBaselineDay = 3;

% Lick bout definition
cfg.boutGapSec  = 2.0;

% Event-lock window (seconds)
cfg.winPre  = 2.0;
cfg.winPost = 2.0;
cfg.fsTimeForEventLock = 30; % because PlotTime_s_30fps implies ~30 fps sampling

% Cumulative lick curve bins
cfg.sessionMaxMin = 20;      % you can increase if sessions are longer
cfg.binWidthSec   = 60;      % 1-minute bins for cumulative curves

% Comparisons requested
cfg.activeCompareDays = struct( ...
    'PRE_last',        5, ...
    'DURING',          6:10, ...
    'POST',            11:13, ...
    'WITHDRAWAL',      14:16, ...
    'REEXPOSURE_first',17);

cfg.passiveCompareDays = struct( ...
    'PRE_last',        5, ...
    'POST',            11:13, ...
    'WITHDRAWAL',      14:16, ...
    'REEXPOSURE',      17:18);

cfg.passiveFocusDays = 6:10;     % passive morphine training days
cfg.passiveVsActive_days_789 = 7:9;
cfg.passiveVsActive_days_1213 = 12:13;

%% ===================== COHORT METADATA =====================
C = cohortTable_NEWCOHORT_2026(); % strict mapping (mouse_key_norm, sex, isPassive, pair_id)

%% ===================== LOCATE LATEST RUN + CSV =====================
[rootOK, runDir] = findLatestRunDir(cfg.rootTry);
if ~rootOK
    error('Cannot find longitudinal_outputs. Update cfg.rootTry.');
end

csvPath = findFileRecursiveNewest(runDir, 'ALL_mice_longitudinal.csv');
if isempty(csvPath)
    error('Could not find ALL_mice_longitudinal.csv under: %s', runDir);
end

ts = char(datetime('now','Format','yyyyMMdd_HHmmss'));
outDir = fullfile(runDir, ['QC_AND_REQUESTED_ANALYSES_' ts]);
if ~exist(outDir,'dir'), mkdir(outDir); end

fprintf('\nUsing runDir:\n  %s\n', runDir);
fprintf('Reading CSV:\n  %s\n', csvPath);
fprintf('Saving outputs to:\n  %s\n\n', outDir);

%% ===================== READ + STRICT SCHEMA CHECK =====================
T = readtable(csvPath, 'VariableNamingRule','preserve');

% Required columns for licking + pupil pipeline
req = { ...
    'mouse_key', 'day_index', 'session_idx', ...
    'PlotTime_s_30fps', 'Lick_TTL', 'Reward_TTL', ...
    'Diameter_px' ...
    };

assertHasVars(T, req, 'Core lick/pupil analysis');

% Optional but strongly expected for PR
hasPR = ismember('TrialRequirement', T.Properties.VariableNames);

% Ensure types
T.mouse_key  = string(T.mouse_key);
T.day_index  = double(T.day_index);
T.session_idx = double(T.session_idx);

% Merge cohort metadata (strict)
T.mouse_key_norm = lower(strrep(strtrim(T.mouse_key)," ",""));
T = outerjoin(T, C, 'Keys','mouse_key_norm','MergeKeys',true,'Type','left');
if any(ismissing(T.isPassive))
    missingKeys = unique(T.mouse_key_norm(ismissing(T.isPassive)));
    fprintf('\nWARNING: Some mouse_key not found in cohort table:\n');
    disp(missingKeys);
    fprintf('They will be kept but excluded from group comparisons.\n\n');
end

% Remove habituation days (global)
T = T(~ismember(T.day_index, cfg.ignoreDays), :);

% Build two variants: include vs exclude transition days
variants = { ...
    struct('name',"INCLUDE_TRANSITIONS",'excludeTransitions',false), ...
    struct('name',"EXCLUDE_TRANSITIONS",'excludeTransitions',true) ...
    };

for v = 1:numel(variants)
    V = variants{v};
    vDir = fullfile(outDir, char(V.name));
    if ~exist(vDir,'dir'), mkdir(vDir); end

    fprintf('=== Variant: %s ===\n', V.name);

    Tuse = T;
    if V.excludeTransitions
        Tuse = Tuse(~ismember(Tuse.day_index, cfg.transitionDays), :);
    end

    % Make phase labels (strict day->phase mapping)
    Tuse.phase = strings(height(Tuse),1);
    Tuse.phase(:) = "NONE";
    Tuse.phase(ismember(Tuse.day_index, cfg.phaseDays.PRE))        = "PRE";
    Tuse.phase(ismember(Tuse.day_index, cfg.phaseDays.DURING))     = "DURING";
    Tuse.phase(ismember(Tuse.day_index, cfg.phaseDays.POST))       = "POST";
    Tuse.phase(ismember(Tuse.day_index, cfg.phaseDays.WITHDRAWAL)) = "WITHDRAWAL";
    Tuse.phase(ismember(Tuse.day_index, cfg.phaseDays.REEXPOSURE)) = "REEXPOSURE";
    Tuse.phase = string(Tuse.phase);

    % ===================== QC TABLES =====================
    qcDir = fullfile(vDir,'QC');
    if ~exist(qcDir,'dir'), mkdir(qcDir); end

    [Sess, Day] = buildSessionAndDayTables(Tuse, hasPR);

    writetable(Sess, fullfile(qcDir,'session_table.csv'));
    writetable(Day,  fullfile(qcDir,'day_table.csv'));

    doQCplots(Sess, Day, qcDir);

    % ===================== LICKING ANALYSES =====================
    lickDir = fullfile(vDir,'LICKING');
    if ~exist(lickDir,'dir'), mkdir(lickDir); end

    doLickSpaghettiPlots(Day, lickDir);                  % lick count / lick rate across days
    doCumulativeLickCurvesByDay(Tuse, lickDir, cfg);     % day-by-day cumulative licking curves
    doEarlyLateCumulative(Tuse, lickDir, cfg);           % early vs late (3-5 vs 6-10) by group

    % Period comparisons requested (active vs passive rules differ)
    periodDir = fullfile(vDir,'PERIOD_COMPARISONS');
    if ~exist(periodDir,'dir'), mkdir(periodDir); end
    doRequestedPeriodComparisons(Day, periodDir, cfg);

    % ===================== PR SCORE (if present) =====================
    if hasPR
        prDir = fullfile(vDir,'PR');
        if ~exist(prDir,'dir'), mkdir(prDir); end
        doPRplots(Day, prDir);
    else
        fprintf('NOTE: TrialRequirement column not present; PR plots skipped.\n');
    end

    % ===================== PUPIL ANALYSES =====================
    pupilDir = fullfile(vDir,'PUPIL');
    if ~exist(pupilDir,'dir'), mkdir(pupilDir); end

    doPupilDayByDayNormalized(Day, pupilDir, cfg);         % normalize to day3 per mouse
    doPupilMorphineVsWaterBoxes(Day, pupilDir, cfg);       % day4-5 vs day12-13 style comparisons

    % Event-locked pupil (reward-locked + lick-bout-locked)
    eventDir = fullfile(vDir,'PUPIL_EVENT_LOCKED');
    if ~exist(eventDir,'dir'), mkdir(eventDir); end
    doEventLockedPupil(Tuse, eventDir, cfg);

    % Special passive focus comparisons
    doPassiveFocusComparisons(Day, pupilDir, cfg);

    % ===================== NON-LICK ASSAYS (if present) =====================
    assayDir = fullfile(vDir,'ASSAYS');
    if ~exist(assayDir,'dir'), mkdir(assayDir); end
    doAssayPlotsAndStats(Tuse, assayDir);

    fprintf('Done variant: %s\n\n', V.name);
end

fprintf('ALL DONE. Outputs at:\n  %s\n', outDir);

end

%% =====================================================================
%% ===================== CORE TABLE BUILDERS ============================
function [Sess, Day] = buildSessionAndDayTables(T, hasPR)
% Session table: one row per mouse-day-session
% Day table: one row per mouse-day (average across sessions)

% Build lick/reward edges at the frame level per session
G = findgroups(T.mouse_key_norm, T.day_index, T.session_idx);

Sess = table();
Sess.mouse_key_norm = splitapply(@(x)x(1), T.mouse_key_norm, G);
Sess.mouse_key      = splitapply(@(x)x(1), string(T.mouse_key), G);
Sess.day_index      = splitapply(@(x)x(1), T.day_index, G);
Sess.session_idx    = splitapply(@(x)x(1), T.session_idx, G);
Sess.phase          = splitapply(@(x)x(1), string(T.phase), G);
Sess.isPassive      = splitapply(@(x)x(1), T.isPassive, G);
Sess.sex            = splitapply(@(x)x(1), string(T.sex), G);
Sess.pair_id        = splitapply(@(x)x(1), string(T.pair_id), G);

% Time
tmin = splitapply(@(x)min(x), T.PlotTime_s_30fps, G);
tmax = splitapply(@(x)max(x), T.PlotTime_s_30fps, G);
Sess.session_dur_s = tmax - tmin;
Sess.session_dur_min = Sess.session_dur_s / 60;

% Lick count (rising edges of Lick_TTL)
Sess.lick_count = splitapply(@(x)countRises(x), T.Lick_TTL, G);
Sess.reward_count = splitapply(@(x)countRises(x), T.Reward_TTL, G);

Sess.licks_per_min = Sess.lick_count ./ max(1e-6, Sess.session_dur_min);

% IEI (lick period) metrics
Sess.iei_mean_s = splitapply(@(tt,lk)ieiMean(tt,lk), T.PlotTime_s_30fps, T.Lick_TTL, G);
Sess.iei_cv     = splitapply(@(tt,lk)ieiCV(tt,lk),   T.PlotTime_s_30fps, T.Lick_TTL, G);

% Pupil mean per session
Sess.pupil_mean_px = splitapply(@(x)nanmean(x), T.Diameter_px, G);

% PR score per session if possible
if hasPR
    Sess.PR_requirement_last = splitapply(@(x)prLast(x), T.TrialRequirement, G);
else
    Sess.PR_requirement_last = nan(height(Sess),1);
end

% Day table: average over sessions per mouse-day
Gd = findgroups(Sess.mouse_key_norm, Sess.day_index);

Day = table();
Day.mouse_key_norm = splitapply(@(x)x(1), Sess.mouse_key_norm, Gd);
Day.mouse_key      = splitapply(@(x)x(1), Sess.mouse_key, Gd);
Day.day_index      = splitapply(@(x)x(1), Sess.day_index, Gd);
Day.phase          = splitapply(@(x)x(1), Sess.phase, Gd);
Day.isPassive      = splitapply(@(x)x(1), Sess.isPassive, Gd);
Day.sex            = splitapply(@(x)x(1), Sess.sex, Gd);
Day.pair_id        = splitapply(@(x)x(1), Sess.pair_id, Gd);

Day.n_sessions     = splitapply(@numel, Sess.session_idx, Gd);

Day.lick_count     = splitapply(@nanmean, Sess.lick_count, Gd);
Day.licks_per_min  = splitapply(@nanmean, Sess.licks_per_min, Gd);
Day.iei_mean_s     = splitapply(@nanmean, Sess.iei_mean_s, Gd);
Day.iei_cv         = splitapply(@nanmean, Sess.iei_cv, Gd);
Day.reward_count   = splitapply(@nanmean, Sess.reward_count, Gd);

Day.pupil_mean_px  = splitapply(@nanmean, Sess.pupil_mean_px, Gd);
Day.PR_requirement_last = splitapply(@nanmean, Sess.PR_requirement_last, Gd);

end

%% =====================================================================
%% ===================== QC PLOTS ======================================
function doQCplots(Sess, Day, outDir)

% Coverage: sessions per mouse
f = figure('Color','w','Position',[60 60 1100 420]);
tiledlayout(1,2,'Padding','compact','TileSpacing','compact');

nexttile;
cats = categorical(Day.mouse_key_norm);
counts = groupsummary(Day,'mouse_key_norm','numel','day_index');
bar(counts.numel_day_index);
set(gca,'XTick',1:height(counts),'XTickLabel',counts.mouse_key_norm,'XTickLabelRotation',45);
ylabel('Days present'); title('Coverage per mouse (days)');
grid on;

nexttile;
histogram(Sess.session_dur_min, 30);
xlabel('Session duration (min)'); ylabel('Count'); title('Session duration distribution');
grid on;

exportgraphics(f, fullfile(outDir,'QC_coverage_and_duration.png'), 'Resolution',300);
close(f);

% Outlier scan: lick_count and pupil_mean
f = figure('Color','w','Position',[60 60 1100 420]);
tiledlayout(1,2,'Padding','compact','TileSpacing','compact');

nexttile;
histogram(Day.lick_count, 30);
xlabel('Mean lick count/day'); ylabel('Mouse-days'); title('Lick count distribution');
grid on;

nexttile;
histogram(Day.pupil_mean_px, 30);
xlabel('Mean pupil diameter (px)'); ylabel('Mouse-days'); title('Pupil mean distribution');
grid on;

exportgraphics(f, fullfile(outDir,'QC_distributions_lick_pupil.png'), 'Resolution',300);
close(f);

writetable(Day, fullfile(outDir,'QC_day_table.csv'));
writetable(Sess, fullfile(outDir,'QC_session_table.csv'));

end

