%% ===================== LICKING: SPAGHETTI =============================
function doLickSpaghettiPlots(Day, outDir)

% Active vs passive spaghetti for lick_count across days
f = figure('Color','w','Position',[60 60 1200 500]);
tiledlayout(1,2,'Padding','compact','TileSpacing','compact');

% ACTIVE
nexttile; hold on;
A = Day(Day.isPassive==0,:);
plotSpaghettiByMouse(A.day_index, A.lick_count, A.mouse_key_norm);
plotMeanBold(A.day_index, A.lick_count);
xlabel('Day'); ylabel('Lick count/day'); title('Spaghetti: Lick count per day (Active)');
grid on;

% PASSIVE
nexttile; hold on;
P = Day(Day.isPassive==1,:);
plotSpaghettiByMouse(P.day_index, P.lick_count, P.mouse_key_norm);
plotMeanBold(P.day_index, P.lick_count);
xlabel('Day'); ylabel('Lick count/day'); title('Spaghetti: Lick count per day (Passive)');
grid on;

exportgraphics(f, fullfile(outDir,'Spaghetti_lick_count_active_vs_passive.png'), 'Resolution',300);
close(f);

% IEI mean (lick period proxy)
f = figure('Color','w','Position',[60 60 1200 500]);
tiledlayout(1,2,'Padding','compact','TileSpacing','compact');

nexttile; hold on;
plotSpaghettiByMouse(A.day_index, A.iei_mean_s, A.mouse_key_norm);
plotMeanBold(A.day_index, A.iei_mean_s);
xlabel('Day'); ylabel('Mean IEI (s)'); title('Spaghetti: Mean IEI (Active)');
grid on;

nexttile; hold on;
plotSpaghettiByMouse(P.day_index, P.iei_mean_s, P.mouse_key_norm);
plotMeanBold(P.day_index, P.iei_mean_s);
xlabel('Day'); ylabel('Mean IEI (s)'); title('Spaghetti: Mean IEI (Passive)');
grid on;

exportgraphics(f, fullfile(outDir,'Spaghetti_meanIEI_active_vs_passive.png'), 'Resolution',300);
close(f);

end

%% =====================================================================
%% ===================== LICKING: CUMULATIVE CURVES =====================
function doCumulativeLickCurvesByDay(T, outDir, cfg)
% Produce day-by-day cumulative lick curves across session time.
% Similar to your attached "Cumulative licking across session".

edges = 0:cfg.binWidthSec:(cfg.sessionMaxMin*60);
binCenters = edges(1:end-1) + cfg.binWidthSec/2;

% Session list
Gsess = findgroups(T.mouse_key_norm, T.day_index, T.session_idx, T.isPassive);
sessKeys = splitapply(@(mk,dy,si,g) string(mk(1))+"|"+dy(1)+"|"+si(1)+"|"+g(1), ...
    T.mouse_key_norm, T.day_index, T.session_idx, T.isPassive, Gsess);
sessKeys = unique(sessKeys);

% Build per-session cumulative curves
S = table();
S.key = sessKeys;
S.isPassive = nan(numel(sessKeys),1);
S.day_index = nan(numel(sessKeys),1);
S.cum = nan(numel(sessKeys), numel(binCenters));

for i=1:numel(sessKeys)
    parts = split(sessKeys(i),"|");
    mk = parts(1);
    dy = str2double(parts(2));
    si = str2double(parts(3));
    gp = str2double(parts(4));

    idx = (T.mouse_key_norm==mk) & (T.day_index==dy) & (T.session_idx==si) & (T.isPassive==gp);
    if ~any(idx), continue; end

    tt = T.PlotTime_s_30fps(idx);
    lk = T.Lick_TTL(idx);

    lickTimes = eventTimesFromTTL(tt, lk);
    cumCounts = zeros(1,numel(binCenters));
    for b=1:numel(binCenters)
        cumCounts(b) = sum(lickTimes <= edges(b+1));
    end

    S.isPassive(i) = gp;
    S.day_index(i) = dy;
    S.cum(i,:) = cumCounts;
end

% Plot per day separately for Active and Passive
daysAll = unique(S.day_index(~isnan(S.day_index)));
daysAll = sort(daysAll);

% Active
f = figure('Color','w','Position',[60 60 1400 600]); hold on;
for d = daysAll'
    Sd = S(S.isPassive==0 & S.day_index==d,:);
    if isempty(Sd), continue; end
    mu = nanmean(Sd.cum,1);
    plot(binCenters/60, mu, 'LineWidth', 2);
end
xlabel('Session time (min)'); ylabel('Mean cumulative licks'); title('Cumulative licking across session (Active)');
grid on;
legend(compose("Day %d", daysAll), 'Location','eastoutside');
exportgraphics(f, fullfile(outDir,'Cumulative_licking_by_day_ACTIVE.png'), 'Resolution',300);
close(f);

% Passive
f = figure('Color','w','Position',[60 60 1400 600]); hold on;
for d = daysAll'
    Sd = S(S.isPassive==1 & S.day_index==d,:);
    if isempty(Sd), continue; end
    mu = nanmean(Sd.cum,1);
    plot(binCenters/60, mu, 'LineWidth', 2);
end
xlabel('Session time (min)'); ylabel('Mean cumulative licks'); title('Cumulative licking across session (Passive)');
grid on;
legend(compose("Day %d", daysAll), 'Location','eastoutside');
exportgraphics(f, fullfile(outDir,'Cumulative_licking_by_day_PASSIVE.png'), 'Resolution',300);
close(f);

end

function doEarlyLateCumulative(T, outDir, cfg)
% Recreate your “Early vs Late sessions” type plot, but consistent with your paradigm:
% early = days 3–5, late = days 6–10 (for licking; PR differs by group).

edges = 0:cfg.binWidthSec:(cfg.sessionMaxMin*60);
binCenters = edges(1:end-1) + cfg.binWidthSec/2;

earlyDays = cfg.phaseDays.PRE;        % 3–5
lateDays  = cfg.phaseDays.DURING;     % 6–10

for gp = [0 1]
    label = tern(gp==0,'ACTIVE','PASSIVE');

    curvesEarly = collectCumCurves(T, gp, earlyDays, edges);
    curvesLate  = collectCumCurves(T, gp, lateDays,  edges);

    if isempty(curvesEarly) || isempty(curvesLate)
        continue;
    end

    muE = mean(curvesEarly,1,'omitnan');
    muL = mean(curvesLate, 1,'omitnan');

    f = figure('Color','w','Position',[60 60 1100 500]); hold on;
    plot(binCenters/60, muE, 'LineWidth', 3);
    plot(binCenters/60, muL, 'LineWidth', 3);
    xlabel('Session time (min)'); ylabel('Mean cumulative licks');
    title(sprintf('Early (days 3–5) vs Late (days 6–10) cumulative licking (%s)', label));
    grid on; legend({'Days 3–5','Days 6–10'}, 'Location','southeast');

    exportgraphics(f, fullfile(outDir, sprintf('Early_vs_Late_Cumulative_%s.png',label)), 'Resolution',300);
    close(f);
end

end

function M = collectCumCurves(T, isPassive, days, edges)
binCenters = edges(1:end-1) + (edges(2)-edges(1))/2;

% session list
rows = T(T.isPassive==isPassive & ismember(T.day_index, days), :);
if isempty(rows), M = []; return; end

G = findgroups(rows.mouse_key_norm, rows.day_index, rows.session_idx);
nSess = max(G);
M = nan(nSess, numel(binCenters));

for s = 1:nSess
    idx = (G==s);
    tt = rows.PlotTime_s_30fps(idx);
    lk = rows.Lick_TTL(idx);
    lickTimes = eventTimesFromTTL(tt, lk);
    cumCounts = zeros(1,numel(binCenters));
    for b=1:numel(binCenters)
        cumCounts(b) = sum(lickTimes <= edges(b+1));
    end
    M(s,:) = cumCounts;
end

end

