%% ===================== PERIOD COMPARISONS REQUESTED ===================
function doRequestedPeriodComparisons(Day, outDir, cfg)

% Active comparisons (your specific day sets)
A = Day(Day.isPassive==0,:);
P = Day(Day.isPassive==1,:);

% ACTIVE: day5 vs (6-10) vs (11-13) vs (14-16) vs day17
namesA = string(fieldnames(cfg.activeCompareDays));
valsA  = cell(numel(namesA),1);
for i=1:numel(namesA)
    dset = cfg.activeCompareDays.(namesA(i));
    valsA{i} = perMouseMeanOverDays(A, dset, 'lick_count');
end
plotPeriodBoxes(valsA, namesA, 'Lick count', 'Active: requested day blocks', fullfile(outDir,'Active_requested_blocks_lickcount.png'));

% PASSIVE: day5 vs (11-13) vs (14-16) vs (17-18)
namesP = string(fieldnames(cfg.passiveCompareDays));
valsP  = cell(numel(namesP),1);
for i=1:numel(namesP)
    dset = cfg.passiveCompareDays.(namesP(i));
    valsP{i} = perMouseMeanOverDays(P, dset, 'lick_count');
end
plotPeriodBoxes(valsP, namesP, 'Lick count', 'Passive: requested day blocks', fullfile(outDir,'Passive_requested_blocks_lickcount.png'));

% Also lick rate and IEI mean (lick period)
valsA = cell(numel(namesA),1);
for i=1:numel(namesA), valsA{i} = perMouseMeanOverDays(A, cfg.activeCompareDays.(namesA(i)), 'licks_per_min'); end
plotPeriodBoxes(valsA, namesA, 'Licks/min', 'Active: requested day blocks', fullfile(outDir,'Active_requested_blocks_lickrate.png'));

valsP = cell(numel(namesP),1);
for i=1:numel(namesP), valsP{i} = perMouseMeanOverDays(P, cfg.passiveCompareDays.(namesP(i)), 'licks_per_min'); end
plotPeriodBoxes(valsP, namesP, 'Licks/min', 'Passive: requested day blocks', fullfile(outDir,'Passive_requested_blocks_lickrate.png'));

valsA = cell(numel(namesA),1);
for i=1:numel(namesA), valsA{i} = perMouseMeanOverDays(A, cfg.activeCompareDays.(namesA(i)), 'iei_mean_s'); end
plotPeriodBoxes(valsA, namesA, 'Mean IEI (s)', 'Active: requested day blocks', fullfile(outDir,'Active_requested_blocks_IEI.png'));

valsP = cell(numel(namesP),1);
for i=1:numel(namesP), valsP{i} = perMouseMeanOverDays(P, cfg.passiveCompareDays.(namesP(i)), 'iei_mean_s'); end
plotPeriodBoxes(valsP, namesP, 'Mean IEI (s)', 'Passive: requested day blocks', fullfile(outDir,'Passive_requested_blocks_IEI.png'));

end

function V = perMouseMeanOverDays(D, days, varname)
% returns one value per mouse (mean over specified days)
Dd = D(ismember(D.day_index, days), :);
if isempty(Dd)
    V = [];
    return;
end
G = findgroups(Dd.mouse_key_norm);
V = splitapply(@(x)nanmean(x), Dd.(varname), G);
end

function plotPeriodBoxes(valsCell, labels, ylab, ttl, savePath)
f = figure('Color','w','Position',[60 60 1200 500]);
data = []; grp = [];
for i=1:numel(valsCell)
    v = valsCell{i};
    data = [data; v(:)];
    grp  = [grp; repmat(i, numel(v), 1)];
end
boxchart(grp, data);
set(gca,'XTick',1:numel(labels),'XTickLabel',labels);
ylabel(ylab); title(ttl); grid on;
exportgraphics(f, savePath, 'Resolution',300);
close(f);
end

%% =====================================================================
%% ===================== PR PLOTS =======================================
function doPRplots(Day, outDir)

f = figure('Color','w','Position',[60 60 1200 500]);
tiledlayout(1,2,'Padding','compact','TileSpacing','compact');

A = Day(Day.isPassive==0,:);
