function doPupilDayByDayNormalized(Day, outDir, cfg)

% baseline per mouse = day3 mean pupil
base = Day(Day.day_index==cfg.pupilBaselineDay, {'mouse_key_norm','pupil_mean_px'});
base = rmmissing(base);

D = Day;
D.pupil_norm_to_day3 = nan(height(D),1);

% map
m = containers.Map(base.mouse_key_norm, base.pupil_mean_px);
for i=1:height(D)
    key = D.mouse_key_norm(i);
    if isKey(m, key) && ~isnan(D.pupil_mean_px(i))
        b = m(key);
        D.pupil_norm_to_day3(i) = (D.pupil_mean_px(i) - b) ./ max(1e-6,b);
    end
end

% Plot active vs passive normalized
f = figure('Color','w','Position',[60 60 1200 500]);
tiledlayout(2,1,'Padding','compact','TileSpacing','compact');

A = D(D.isPassive==0,:);
P = D(D.isPassive==1,:);

nexttile; hold on;
plotSpaghettiByMouse(A.day_index, A.pupil_norm_to_day3, A.mouse_key_norm);
plotMeanBold(A.day_index, A.pupil_norm_to_day3);
xlabel('Day'); ylabel('\Delta pupil / baseline(day3)'); title('Pupil normalized to day3 baseline (Active)');
grid on;

nexttile; hold on;
plotSpaghettiByMouse(P.day_index, P.pupil_norm_to_day3, P.mouse_key_norm);
plotMeanBold(P.day_index, P.pupil_norm_to_day3);
xlabel('Day'); ylabel('\Delta pupil / baseline(day3)'); title('Pupil normalized to day3 baseline (Passive)');
grid on;

exportgraphics(f, fullfile(outDir,'Pupil_normalized_to_day3_active_vs_passive.png'), 'Resolution',300);
close(f);

writetable(D, fullfile(outDir,'DayTable_with_pupil_norm_to_day3.csv'));

end

