%% ===================== PUPIL: EVENT-LOCKED ============================
function doEventLockedPupil(T, outDir, cfg)
% Reward-locked pupil (±2s) baseline = [-2,0)
% Lick-bout-locked pupil (bout gap = 2s) baseline = [-2,0)
% Lick bouts separated into reward-causing vs non-reward bouts

% Build event-locked averages by group and by day-blocks of interest:
% - Active early (3-5) vs during (6-10)
% - Passive early (3-5) vs during (6-10) [forced reward period]
% plus a global (all days combined) per group

blocks = struct();
blocks(1).name = "Early_3to5"; blocks(1).days = 3:5;
blocks(2).name = "During_6to10"; blocks(2).days = 6:10;
blocks(3).name = "Post_11to13"; blocks(3).days = 11:13;

for gp = [0 1]
    gLabel = tern(gp==0,'Active','Passive');

    % Reward-locked
    for b = 1:numel(blocks)
        days = blocks(b).days;
        [tvec, mu] = eventLockedMean(T, gp, days, cfg, "reward");
        if ~isempty(mu)
            f = figure('Color','w','Position',[60 60 900 500]);
            plot(tvec, mu, 'LineWidth',3);
            xlabel('Time from event (s)'); ylabel('\Delta pupil (baseline-subtracted)');
            title(sprintf('Reward-locked pupil (%s) — %s (days %s)', gLabel, blocks(b).name, num2str(days)));
            grid on;
            exportgraphics(f, fullfile(outDir, sprintf('RewardLocked_%s_%s.png', gLabel, blocks(b).name)), 'Resolution',300);
            close(f);
        end
    end

    % Lick-bout-locked (reward-causing vs non-reward)
    for b = 1:numel(blocks)
        days = blocks(b).days;

        [tvec, muR] = eventLockedMean(T, gp, days, cfg, "lickbout_reward");
        [~,   muN] = eventLockedMean(T, gp, days, cfg, "lickbout_noreward");

        if ~isempty(muR) || ~isempty(muN)
            f = figure('Color','w','Position',[60 60 900 500]); hold on;
            if ~isempty(muR), plot(tvec, muR, 'LineWidth',3); end
            if ~isempty(muN), plot(tvec, muN, '--', 'LineWidth',3); end
            xlabel('Time from event (s)'); ylabel('\Delta pupil (baseline-subtracted)');
            title(sprintf('Lick-bout-locked pupil (%s) — %s', gLabel, blocks(b).name));
            grid on;
            legendEntries = {};
            if ~isempty(muR), legendEntries{end+1} = 'Reward-causing bouts'; end %#ok<AGROW>
            if ~isempty(muN), legendEntries{end+1} = 'Non-reward bouts'; end %#ok<AGROW>
            if ~isempty(legendEntries), legend(legendEntries,'Location','best'); end
            exportgraphics(f, fullfile(outDir, sprintf('LickBoutLocked_%s_%s.png', gLabel, blocks(b).name)), 'Resolution',300);
            close(f);
        end
    end
end

end

function [tvec, mu] = eventLockedMean(T, isPassive, days, cfg, mode)
% mode:
%  "reward"             : reward rising edges
%  "lickbout_reward"    : lick-bout onset where a reward occurs within 2s after onset
%  "lickbout_noreward"  : lick-bout onset where no reward occurs within 2s after onset

rows = T(T.isPassive==isPassive & ismember(T.day_index, days), :);
if isempty(rows)
    tvec = []; mu = []; return;
end

tvec = (-cfg.winPre : 1/cfg.fsTimeForEventLock : cfg.winPost)';
snips = [];

G = findgroups(rows.mouse_key_norm, rows.day_index, rows.session_idx);
nSess = max(G);

for s = 1:nSess
    idx = (G==s);
    tt = rows.PlotTime_s_30fps(idx);
    pup = rows.Diameter_px(idx);
    lk  = rows.Lick_TTL(idx);
    rw  = rows.Reward_TTL(idx);

    % drop NaN pupil
    ok = ~isnan(tt) & ~isnan(pup);
    tt = tt(ok); pup = pup(ok); lk = lk(ok); rw = rw(ok);

    if numel(tt) < 10, continue; end

    switch mode
        case "reward"
            ev = eventTimesFromTTL(tt, rw);

        case "lickbout_reward"
            ev = lickBoutOnsets(tt, lk, cfg.boutGapSec);
            ev = ev( boutHasReward(tt, rw, ev, 2.0) );

        case "lickbout_noreward"
            ev = lickBoutOnsets(tt, lk, cfg.boutGapSec);
            ev = ev( ~boutHasReward(tt, rw, ev, 2.0) );

        otherwise
            error('Unknown mode: %s', mode);
    end

    for e = 1:numel(ev)
        t0 = ev(e);
        % baseline window [-winPre, 0)
        baseMask = (tt >= (t0-cfg.winPre)) & (tt < t0);
        if nnz(baseMask) < 5, continue; end
        base = mean(pup(baseMask), 'omitnan');

        % sample onto fixed tvec
        tq = t0 + tvec;
        pq = interp1(tt, pup, tq, 'linear', nan);
        pq = pq - base;

        if nnz(~isnan(pq)) > 0.7*numel(pq)
            snips(:, end+1) = pq; %#ok<AGROW>
        end
    end
end

if isempty(snips)
    mu = [];
else
    mu = mean(snips, 2, 'omitnan');
end

end

function onsets = lickBoutOnsets(tt, lkTTL, gapSec)
lickTimes = eventTimesFromTTL(tt, lkTTL);
if isempty(lickTimes), onsets = []; return; end
d = [inf; diff(lickTimes(:))];
starts = lickTimes(d >= gapSec);
onsets = starts(:);
end

function tf = boutHasReward(tt, rwTTL, boutOnsets, winSec)
rTimes = eventTimesFromTTL(tt, rwTTL);
tf = false(size(boutOnsets));
if isempty(rTimes), return; end
for i=1:numel(boutOnsets)
    tf(i) = any(rTimes >= boutOnsets(i) & rTimes <= (boutOnsets(i)+winSec));
end
end

