%% ===================== ASSAYS: TST / HOT / IMMERSION / STRAUB =========
function doAssayPlotsAndStats(T, outDir)
% These are expected to be present in ALL_mice_longitudinal.csv if you merged them:
%   Immersion_Latency_s
%   HOT_Frames_Nonmoving
%   TST_Frames_Nonmoving
%   Straub (varies by your manual scoring export)
%
% This function:
% - Extracts one value per mouse-day (unique non-NaN)
% - Plots Active vs Passive means per day (if multiple days)
% - Makes 4-group boxplots for day5/day9 when available (as in your examples)

varsToTry = { ...
    'Immersion_Latency_s', ...
    'HOT_Frames_Nonmoving', ...
    'TST_Frames_Nonmoving' ...
    };

% Straub variable name(s) can differ depending on manual scoring table.
% Add common candidates here WITHOUT guessing columns beyond this list:
straubCandidates = { ...
    'Straub_Score', 'StraubTail_Score', 'Straub', 'StraubTail' ...
    };

allVars = [varsToTry, straubCandidates];

for i=1:numel(allVars)
    vn = allVars{i};
    if ~ismember(vn, T.Properties.VariableNames)
        continue;
    end

    D = extractOneValuePerMouseDay(T, vn);
    if isempty(D), continue; end

    % Active vs passive means per day
    f = figure('Color','w','Position',[60 60 1000 450]); hold on;
    days = unique(D.day_index); days = sort(days);
    muA = nan(size(days)); muP = nan(size(days));
    for d=1:numel(days)
        dd = days(d);
        muA(d) = mean(D.value(D.day_index==dd & D.isPassive==0), 'omitnan');
        muP(d) = mean(D.value(D.day_index==dd & D.isPassive==1), 'omitnan');
    end
    plot(days, muA, '-o', 'LineWidth',2);
    plot(days, muP, '-o', 'LineWidth',2);
    xlabel('Day'); ylabel(vn); title(sprintf('%s: Active vs Passive means per day', vn));
    grid on; legend({'Active','Passive'},'Location','best');
    exportgraphics(f, fullfile(outDir, sprintf('%s_means_per_day.png',vn)), 'Resolution',300);
    close(f);

    % 4-group day5/day9 style boxplot (if those days exist)
    if any(days==5) && any(days==9)
        v5A = D.value(D.day_index==5 & D.isPassive==0);
        v5P = D.value(D.day_index==5 & D.isPassive==1);
        v9A = D.value(D.day_index==9 & D.isPassive==0);
        v9P = D.value(D.day_index==9 & D.isPassive==1);

        f = figure('Color','w','Position',[60 60 1000 450]);
        data = [v5A(:); v5P(:); v9A(:); v9P(:)];
        grp  = [repmat("Day5_Active",numel(v5A),1); repmat("Day5_Passive",numel(v5P),1); ...
                repmat("Day9_Active",numel(v9A),1); repmat("Day9_Passive",numel(v9P),1)];
        boxchart(categorical(grp), data);
        ylabel(vn); title(sprintf('%s: Day5/Day9 Active/Passive boxplot', vn));
        grid on;
        exportgraphics(f, fullfile(outDir, sprintf('%s_box_day5_day9.png',vn)), 'Resolution',300);
        close(f);
    end

    writetable(D, fullfile(outDir, sprintf('%s_oneValuePerMouseDay.csv',vn)));
end

end

function D = extractOneValuePerMouseDay(T, varname)
% Take unique non-NaN value per mouse-day (if multiple, take nanmean).
G = findgroups(T.mouse_key_norm, T.day_index);
mk = splitapply(@(x)x(1), T.mouse_key_norm, G);
dy = splitapply(@(x)x(1), T.day_index, G);
gp = splitapply(@(x)x(1), T.isPassive, G);
val = splitapply(@(x)nanmean(x), T.(varname), G);

D = table(string(mk), dy, gp, val, 'VariableNames',{'mouse_key_norm','day_index','isPassive','value'});
D = D(~isnan(D.value), :);
end

