function assertHasVars(T, vars, context)
missing = vars(~ismember(vars, T.Properties.VariableNames));
if ~isempty(missing)
    fprintf('\nSCHEMA ERROR in %s.\nMissing required columns:\n', context);
    disp(missing(:));
    error('Fix CSV schema or update required variable list in the script.');
end
end

function [ok, runDir] = findLatestRunDir(rootTry)
ok = false; runDir = "";

tryPath = rootTry;
if ~exist(tryPath,'dir')
    here = pwd; cand = here;
    for up=1:6
        p = fullfile(cand,'longitudinal_outputs');
        if exist(p,'dir'), tryPath = p; break; end
        cand = fileparts(cand);
    end
end
if ~exist(tryPath,'dir'), return; end

d = dir(fullfile(tryPath,'run_*'));
if isempty(d), return; end
[~,idx] = max([d.datenum]);
runDir = fullfile(d(idx).folder, d(idx).name);
ok = true;
end

function fp = findFileRecursiveNewest(rootDir, fileName)
d = dir(fullfile(rootDir, '**', fileName));
if isempty(d), fp = ""; return; end
[~,ix] = max([d.datenum]);
fp = fullfile(d(ix).folder, d(ix).name);
end

function n = countRises(ttl)
x = double(ttl(:) > 0.5);
n = sum(diff([0; x])==1);
end

function times = eventTimesFromTTL(tt, ttl)
x = double(ttl(:) > 0.5);
r = find(diff([0; x])==1);
times = tt(r);
times = times(~isnan(times));
end

function m = ieiMean(tt, lkTTL)
lickTimes = eventTimesFromTTL(tt, lkTTL);
if numel(lickTimes) < 2, m = nan; return; end
d = diff(lickTimes);
m = mean(d,'omitnan');
end

function c = ieiCV(tt, lkTTL)
lickTimes = eventTimesFromTTL(tt, lkTTL);
if numel(lickTimes) < 3, c = nan; return; end
d = diff(lickTimes);
mu = mean(d,'omitnan');
sd = std(d,'omitnan');
c = sd / max(1e-6, mu);
end

function v = prLast(x)
% TrialRequirement may be per-frame/per-trial; we take the last non-NaN value.
x = x(:);
x = x(~isnan(x));
if isempty(x), v = nan; else, v = x(end); end
end

function plotSpaghettiByMouse(xDay, yVal, mouseKeys)
keys = unique(mouseKeys);
for i=1:numel(keys)
    idx = mouseKeys==keys(i);
    xd = xDay(idx); yd = yVal(idx);
    [xd,ord] = sort(xd); yd = yd(ord);
    plot(xd, yd, '-o', 'LineWidth',1.2, 'MarkerSize',4);
end
end

function plotMeanBold(xDay, yVal)
days = unique(xDay); days = sort(days);
mu = nan(size(days));
for i=1:numel(days)
    mu(i) = mean(yVal(xDay==days(i)), 'omitnan');
end
plot(days, mu, '-k', 'LineWidth',3);
end

function s = tern(cond, a, b)
if cond, s = a; else, s = b; end
end
